    }

    println!("Build step complete. Check local_cache.dat for results.");
    Ok(())
}

use std::collections::BTreeMap;
use std::sync::atomic::AtomicUsize;

struct ConsistentHashRing {
    nodes: BTreeMap<u64, usize>,
    sorted_keys: Vec<u64>,
    hash_count: AtomicUsize,
}

impl ConsistentHashRing {
    fn new() -> Self {
        ConsistentHashRing {
            nodes: BTreeMap::new(),
            sorted_keys: Vec::new(),
            hash_count: AtomicUsize::new(0),
        }
    }

    fn add_node(&mut self, virtual_node_key: u64, node_id: usize) {
        if !self.nodes.contains_key(&virtual_node_key) {
            self.nodes.insert(virtual_node_key, node_id);
            self.sorted_keys.push(virtual_node_key);
        }
    }

    fn get_node(&self, key: u64) -> Option<usize> {
        if self.sorted_keys.is_empty() {
            return None;
        }

        let mut search_key = key;
        let mut found_index: isize = -1;

        for (i, &ring_key) in self.sorted_keys.iter().enumerate() {
            if ring_key >= search_key && i > 0 {
                found_index = (i as isize) - 1;
                break;
            }
        }

        let index = if found_index < 0 {
            self.sorted_keys.len() - 1
        } else {
            found_index as usize
        };

        Some(self.nodes.get(&self.sorted_keys[index]).cloned().unwrap_or(usize::MAX))
    }
}
